1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Base premiums for single main items (R1, R3 fee, first insurance) ---
6	  it("empty item list → premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("single plain sword for a newcomer first contract → premium 115 G (100 base + 10 first + 5 fee)");
14	  it.todo("single plain amulet for a newcomer first contract → premium 71 G (60 base + 6 first + 5 fee)");
15	  it.todo("single plain staff for a newcomer first contract → premium 93 G (80 base + 8 first + 5 fee)");
16	  it.todo("single plain potion for a newcomer first contract → premium 49 G (40 base + 4 first + 5 fee)");
17	
18	  // --- Component pricing and block discount (R1, R2) ---
19	  it.todo("single rune for a newcomer first contract → premium 33 G (25 base + 2.5 first + 5 fee = 32.5 → up to 33)");
20	  it.todo("2 runes (no block) → base 50 G; premium 60 G for newcomer first contract (50 + 5 first + 5 fee)");
21	  it.todo("3 runes (block applies) → base 60 G; premium 71 G for newcomer first contract (60 + 6 first + 5 fee)");
22	  it.todo("4 runes (no block) → base 100 G; premium 115 G for newcomer first contract (100 + 10 first + 5 fee)");
23	  it.todo("7 runes (no block) → base 175 G; premium 198 G for newcomer first contract (175 + 17.5 first + 5 fee = 197.5 → up to 198)");
24	
25	  // --- "Alike" components — same type only ---
26	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types); premium 88 G newcomer first (75 + 7.5 first + 5 fee = 87.5 → 88)");
27	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks); premium 137 G newcomer first (120 + 12 first + 5 fee)");
28	
29	  // --- Item-specific modifiers ---
30	  it.todo("cursed steel sword enchantment 3, newcomer first → premium 165 G (100 + 50 curse + 10 first + 5 fee) [integration example]");
31	  it.todo("steel sword enchantment 5, newcomer first → premium 145 G (100 + 30 high-ench + 10 first + 5 fee) [threshold]");
32	  it.todo("steel sword enchantment 4, newcomer first → premium 115 G (no high-ench surcharge)");
33	  it.todo("cursed steel sword enchantment 5, newcomer first → premium 195 G (100 + 50 curse + 30 high-ench + 10 first + 5 fee)");
34	
35	  // --- Multi-item modifier scope ---
36	  it.todo("cursed sword + plain amulet, newcomer first → premium 231 G (sum base 160 + 50 curse on sword + 16 first on 160 + 5 fee)");
37	
38	  // --- Policy-wide modifiers ---
39	  it.todo("plain sword for customer with exactly 2 years, first contract → premium 95 G (100 − 20 loyalty + 10 first + 5 fee) [loyalty threshold]");
40	  it.todo("long-standing 2nd contract: customer 3y, second quote, cursed sword enchantment 7 → premium 160 G [integration example]");
41	
42	  // --- Claims: cap, deductible, clauses ---
43	  it.todo("standard claim: steel sword enchantment 3, damage 500 → payout 400 G; remainingCap 1600 G (cap 2000 − 400)");
44	  it.todo("standard claim on a rune (no enchantment/material), damage 200 → payout 100 G; remainingCap 400 G (cap 500 − 100)");
45	  it.todo("high-enchantment clause: steel sword enchantment 9, damage 1000 → payout 400 G (500 − 100)");
46	  it.todo("dragon-material clause: dragon sword enchantment 5, damage 800 → payout 700 G (800 − 100)");
47	  it.todo("both clauses (50 % wins): dragon sword enchantment 9, damage 1000 → payout 400 G");
48	  it.todo("enchantment threshold exactly 8: dragon sword enchantment 8, damage 1000 → payout 400 G");
49	  it.todo("payout rounded down: dragon sword enchantment 9, damage 801 → payout 300 G (400.5 − 100 = 300.5 → down to 300)");
50	
51	  // --- Deductible per damage event ---
52	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible applied once per damaged item); remainingCap 2600 G");
53	
54	  // --- Multiple items of the same type ---
55	  it.todo("policy with two swords → insurance sum 2000, cap 4000; dragon attack damages both (two entries 500 each) → payout 800 G; remainingCap 3200 G");
56	
57	  // --- Cap exhaustion ---
58	  it.todo("single sword (cap 2000), two successive 1500 G claims → first {payout 1400, remainingCap 600}, second {payout 600, remainingCap 0}");
59	
60	  // --- Insurance sum independent of block discount ---
61	  it.todo("policy with sword + 3 runes → insurance sum 1750 (block does not change insurance sum), cap 3500; small claim verifies remainingCap");
62	
63	  // --- Cap is based on unmodified insurance value (not on modified premium) ---
64	  it.todo("cursed sword policy → cap is 2000 G (based on unmodified insurance value 1000, not on the modified premium); verify via a 1500 G claim that yields payout 1400 and remainingCap 600");
65	
66	  // --- Error cases (CLI exit codes) ---
67	  it.todo("CLI error: quote contains an unknown item type (e.g. broomstick) → non-zero exit, error on stderr, no results on stdout");
68	  it.todo("CLI error: claim references an item not part of the policy (amulet damage when only sword insured) → non-zero exit, error on stderr");
69	  it.todo("CLI error: damage entry with negative amount (−200) → non-zero exit, error on stderr");
70	  it.todo("CLI error: more damages of a type than items insured (two sword damages, one sword insured) → non-zero exit");
71	});
